mapper.select:
select *
from io_order_detail
where delete_flag = 0

    and product_id = #{query.productId}


    and biz_date  >=  #{query.bizDateStart}


    and biz_date  <=  #{query.bizDateEnd}


    and order_type = #{query.orderType}

order by biz_date desc, order_id desc, id desc

select coalesce(sum(case
                        when order_type = 1 then qty
                        else 0
    end), 0) as inboundQty,
       coalesce(sum(case
                        when order_type = 2 then qty
                        else 0
           end), 0) as outboundQty
from io_order_detail
where delete_flag = 0

    and product_id = #{query.productId}


    and biz_date  >=  #{query.bizDateStart}


    and biz_date  <=  #{query.bizDateEnd}


    and order_type = #{query.orderType}

select coalesce(sum(case
                        when d.order_type = 1 then d.qty
                        else -d.qty
    end), 0)
from io_order_detail d
where d.product_id = #{productId}
  and d.id < #{detailId}
  and delete_flag = 0

select t.id as detailId, coalesce(sum(case when d.order_type = 1 then d.qty else -d.qty end), 0) as currentStockQty from io_order_detail t join io_order_detail d on d.product_id = t.product_id and d.delete_flag = 0 and d.biz_date <= t.biz_date and d.order_id <= t.order_id and d.id <= t.id where t.delete_flag = 0 and t.id in
#{detailId}
group by t.id
